import { Routes, Route } from "react-router-dom";
import RPAdmin from "./np-admin/app";

const AllRoutes = () => {
	return (
		<Routes>
			<Route exact path="/" component={RPAdmin} />
		</Routes>
	);
};

export default AllRoutes;
